        self.current_link = None
        self.in_link = False
        self.last_form = None

    def handle_starttag(self, tag, attrs):
        if tag == 'a':
            for attr, value in attrs:
                if attr == 'href' and 'sec-filing' in value:
                    self.current_link = value
                    self.in_link = True
                    break
